# ─── 辅助函数 ─────────────────────────────────────────────────────────────────
def chg_class(v):
    if v is None: return "chg-flat"
    if v > 0: return "chg-up"
    if v < 0: return "chg-down"
    return "chg-flat"

def chg_str(v, suffix="%", decimals=1):
    if v is None: return "—"
    sign = "+" if v > 0 else ""
    return f"{sign}{v:.{decimals}f}{suffix}"

def attr_badge(media_pct, creative_pct):
    if media_pct >= 60:
        return '<span class="attr-badge attr-media">媒体侧主导</span>'
    elif creative_pct >= 60:
        return '<span class="attr-badge attr-creative">创意侧主导</span>'
    else:
        return '<span class="attr-badge attr-both">媒体+创意共同</span>'

def type_tag(t):
    tags = {
        "media":    '<span class="tag tag-warn">媒体侧CPM↑</span>',
        "creative": '<span class="tag tag-warn">创意侧IPM↓</span>',
        "both":     '<span class="tag tag-warn">CPM↑+IPM↓</span>',
        "ok":       '<span class="tag tag-ok">正常/改善</span>',
    }
    return tags.get(t, "")

def render_publishers(pubs):
    if not pubs:
        return '<div class="pending-msg">📊 Publisher 数据待查（下次更新补充）</div>'
    rows = ""
    for p in pubs:
        share_chg = p.get("share_chg")
        share_cls = "share-up" if (share_chg or 0) > 1 else ("share-down" if (share_chg or 0) < -1 else "chg-flat")
        share_str = chg_str(share_chg, suffix="pp") if share_chg else "—"
        rows += f"""
        <tr>
          <td class="name-cell" title="{p['name']}">{p['name'][:35]}{'…' if len(p['name'])>35 else ''}</td>
          <td>{p.get('prev_share', 0):.1f}%</td>
          <td>{p.get('curr_share', 0):.1f}%</td>
          <td class="{share_cls}">{share_str}</td>
          <td class="{chg_class(p.get('cpi_chg'))}">{chg_str(p.get('cpi_chg'))}</td>
          <td class="{chg_class(p.get('cpm_chg'))}">{chg_str(p.get('cpm_chg'))}</td>
          <td class="{chg_class(p.get('ipm_chg'))}">{chg_str(p.get('ipm_chg'))}</td>
          <td>{type_tag(p.get('type','ok'))}</td>
        </tr>"""
    return f"""
    <div class="table-title"><span class="icon icon-pub">P</span>Top Publishers 明细（媒体侧）</div>
    <table>
      <tr><th>Publisher</th><th>上期占比</th><th>本期占比</th><th>占比变化</th>
          <th>CPI 变化</th><th>CPM 变化</th><th>IPM 变化</th><th>类型</th></tr>
      {rows}
    </table>"""

def render_formats(fmts):
    if not fmts:
        return '<div class="pending-msg">🎨 Creative Format 数据待查（下次更新补充）</div>'
    rows = ""
    for f in fmts:
        share_chg = f.get("share_chg")
        share_cls = "share-up" if (share_chg or 0) > 1 else ("share-down" if (share_chg or 0) < -1 else "chg-flat")
        share_str = chg_str(share_chg, suffix="pp") if share_chg else "—"
        rows += f"""
        <tr>
          <td><span class="fmt-badge">{f['name']}</span></td>
          <td>{f.get('prev_share', 0):.1f}%</td>
          <td>{f.get('curr_share', 0):.1f}%</td>
          <td class="{share_cls}">{share_str}</td>
          <td class="{chg_class(f.get('cpi_chg'))}">{chg_str(f.get('cpi_chg'))}</td>
          <td class="{chg_class(f.get('ipm_chg'))}">{chg_str(f.get('ipm_chg'))}</td>
          <td class="{chg_class(f.get('ctr_chg'))}">{chg_str(f.get('ctr_chg'), suffix='pp')}</td>
          <td>{type_tag(f.get('type','ok'))}</td>
        </tr>"""
    return f"""
    <div class="table-title"><span class="icon icon-fmt">F</span>Creative Format 明细（创意侧）</div>
    <table>
      <tr><th>Format</th><th>上期占比</th><th>本期占比</th><th>占比变化</th>
          <th>CPI 变化</th><th>IPM 变化</th><th>CTR 变化</th><th>类型</th></tr>
      {rows}
    </table>"""

def render_country_block(c):
    media = c["media_pct"]
    creative = c["creative_pct"]
    mbar = max(0, min(100, media))
    cbar = max(0, min(100, creative))
    if mbar + cbar > 100:
        total = mbar + cbar; mbar = int(mbar/total*100); cbar = 100-mbar

    cpi_chg = c["cpi_chg"]
    if cpi_chg >= 0:
        cpi_badge_cls = "cpi-up"
        cpi_label = f"CPI {chg_str(cpi_chg)}"
    else:
        cpi_badge_cls = "cpi-down"
        cpi_label = f"CPI {chg_str(cpi_chg)}"

    campaigns_html = ""
    if c.get("campaigns"):
        rows = ""
        for cam in c["campaigns"]:
            cpi_prev = f"${cam['prev_cpi']:.2f}" if cam.get("prev_cpi") else "—"
            cpi_curr = f"${cam['curr_cpi']:.2f}" if cam.get("curr_cpi") else "—"
            rows += f"""
            <tr>
              <td class="name-cell" title="{cam['name']}">{cam['name'][:40]}{'…' if len(cam['name'])>40 else ''}</td>
              <td>{cpi_prev}</td><td>{cpi_curr}</td>
              <td class="{chg_class(cam['cpi_chg'])}">{chg_str(cam['cpi_chg'])}</td>
              <td class="{chg_class(cam['cpm_chg'])}">{chg_str(cam['cpm_chg'])}</td>
              <td class="{chg_class(cam['ipm_chg'])}">{chg_str(cam['ipm_chg'])}</td>
              <td>{type_tag(cam['type'])}</td>
            </tr>"""
        campaigns_html = f"""
        <div class="table-title"><span class="icon icon-creative">C</span>Campaign 明细</div>
        <table>
          <tr><th>Campaign</th><th>CPI 上期</th><th>CPI 本期</th><th>CPI 变化</th>
              <th>CPM 变化</th><th>IPM 变化</th><th>类型</th></tr>
          {rows}
        </table>"""

    exchanges_html = ""
    if c.get("exchanges"):
        rows = ""
        for ex in c["exchanges"]:
            share_chg = ex["share_chg"]
            share_str = f"{chg_str(share_chg, suffix='pp')} {'⚠' if share_chg >= 2 else ('↓' if share_chg <= -2 else '')}" if share_chg != 0 else "—"
            share_cls = "share-up" if share_chg > 1 else ("share-down" if share_chg < -1 else "chg-flat")
            rows += f"""
            <tr>
              <td>{ex['name']}</td>
              <td>{ex['prev_share']:.1f}%</td><td>{ex['curr_share']:.1f}%</td>
              <td class="{share_cls}">{share_str}</td>
              <td class="{chg_class(ex['cpi_chg'])}">{chg_str(ex['cpi_chg'])}</td>
              <td class="{chg_class(ex['prev_cpm_chg'])}">{chg_str(ex['prev_cpm_chg'])}</td>
              <td class="{chg_class(ex['ipm_chg'])}">{chg_str(ex['ipm_chg'])}</td>
              <td>{type_tag(ex['type'])}</td>
            </tr>"""
        exchanges_html = f"""
        <div class="table-title"><span class="icon icon-media">M</span>Exchange 明细（媒体侧）</div>
        <table>
          <tr><th>Exchange</th><th>上期占比</th><th>本期占比</th><th>占比变化</th>
              <th>CPI 变化</th><th>CPM 变化</th><th>IPM 变化</th><th>类型</th></tr>
          {rows}
        </table>"""

    publishers_html = render_publishers(c.get("publishers", []))
    formats_html = render_formats(c.get("formats", []))

    ctr_row = ""
    if c.get("prev_ctr") is not None:
        ctr_chg = c["curr_ctr"] - c["prev_ctr"]
        cvr_chg = (c["curr_cvr"] - c["prev_cvr"]) / c["prev_cvr"] * 100 if c["prev_cvr"] else 0
        ctr_row = f"""
        <div class="metric-pill"><div class="m-label">CTR</div><div class="m-val">{c['prev_ctr']:.1f}%→{c['curr_ctr']:.1f}%</div><div class="m-chg {chg_class(ctr_chg)}">{chg_str(ctr_chg, suffix='pp')}</div></div>
        <div class="metric-pill"><div class="m-label">CVR</div><div class="m-val">{c['prev_cvr']:.2f}%→{c['curr_cvr']:.2f}%</div><div class="m-chg {chg_class(cvr_chg)}">{chg_str(cvr_chg)}</div></div>"""

    return f"""
  <div class="country-block">
    <div class="country-header">
      <div class="country-name">{c['flag']} {c['name']}</div>
      <span class="cpi-badge {cpi_badge_cls}">{cpi_label}</span>
      {attr_badge(media, creative)}
      <div style="margin-left:auto;font-size:12px;color:#94a3b8;">${c['prev_cpi']:.2f} → ${c['curr_cpi']:.2f}</div>
    </div>
    <div class="attr-section">
      <div class="attr-bar-wrap">
        <div style="font-size:11px;color:#64748b;width:56px;">归因</div>
        <div class="attr-bar">
          <div class="attr-media-fill" style="width:{mbar}%"></div>
          <div class="attr-creative-fill" style="width:{cbar}%"></div>
        </div>
        <div class="attr-labels">
          <span><span class="dot" style="background:#f97316"></span>媒体侧 {media}%（CPM {chg_str(c['cpm_chg'])}）</span>
          <span><span class="dot" style="background:#a855f7"></span>创意侧 {creative}%（IPM {chg_str(c['ipm_chg'])}）</span>
        </div>
      </div>
    </div>
    <div class="metrics-grid">
      <div class="metric-pill"><div class="m-label">CPI</div><div class="m-val">${c['prev_cpi']:.2f}→${c['curr_cpi']:.2f}</div><div class="m-chg {chg_class(cpi_chg)}">{chg_str(cpi_chg)}</div></div>
      <div class="metric-pill"><div class="m-label">CPM</div><div class="m-val">${c['prev_cpm']:.2f}→${c['curr_cpm']:.2f}</div><div class="m-chg {chg_class(c['cpm_chg'])}">{chg_str(c['cpm_chg'])}</div></div>
      <div class="metric-pill"><div class="m-label">IPM</div><div class="m-val">{c['prev_ipm']:.2f}→{c['curr_ipm']:.2f}</div><div class="m-chg {chg_class(c['ipm_chg'])}">{chg_str(c['ipm_chg'])}</div></div>
      {ctr_row}
      <div class="metric-pill"><div class="m-label">花费</div><div class="m-val">${c['prev_spend']:,.0f}→${c['curr_spend']:,.0f}</div></div>
      <div class="metric-pill"><div class="m-label">安装</div><div class="m-val">{c['prev_installs']:,}→{c['curr_installs']:,}</div></div>
    </div>
    <div class="table-section">
      {campaigns_html}
      {exchanges_html}
      {publishers_html}
      {formats_html}
    </div>
    <div class="conclusion"><strong>结论：</strong>{c['conclusion']}</div>
  </div>"""


def render_product_tab(prod):
    """Render tab content for one product."""
    key = prod["key"]
    os_label = prod["os"]
    os_cls = "os-ios" if os_label == "iOS" else "os-and"

    # no_data placeholder
    if prod.get("no_data"):
        return f"""
<div id="{key}" class="tab-content">
  <div class="product-header">
    <span class="product-id-badge">{prod['label']}</span>
    <span class="{os_cls} os-badge">{os_label}</span>
    <h2>{prod['name']} · {prod['product_id']}</h2>
    <span style="margin-left:auto;font-size:12px;background:#fef9c3;color:#854d0e;border:1px solid #fde68a;border-radius:20px;padding:2px 10px;">⏳ 数据待查</span>
  </div>
  <div style="padding:40px;text-align:center;color:#94a3b8;font-size:13px;">
    本产品数据将在下次周报更新时填入
  </div>
</div>"""

    # no_alert product (e.g. 1180 Android)
    if prod.get("no_alert"):
        rows = ""
        for c in prod.get("all_countries", []):
            cls = "chg-up" if c["cpi_chg"] > 0 else "chg-down"
            badge_bg = "#fef2f2" if c["cpi_chg"] > 0 else "#f0fdf4"
            badge_col = "#dc2626" if c["cpi_chg"] > 0 else "#16a34a"
            badge_border = "#fecaca" if c["cpi_chg"] > 0 else "#bbf7d0"
            badge = f'<span style="font-size:11px;padding:1px 6px;border-radius:10px;background:{badge_bg};color:{badge_col};border:1px solid {badge_border}">{chg_str(c["cpi_chg"])}</span>'
            if c.get("prev_cpm") is not None and c.get("curr_cpm") is not None:
                cpm_v = c["curr_cpm"] - c["prev_cpm"]
                cpm_display = f"${c['prev_cpm']:.2f}→${c['curr_cpm']:.2f}"
            else:
                cpm_v = c.get("cpm_chg")
                cpm_display = chg_str(c.get("cpm_chg"))
            if c.get("prev_ipm") is not None and c.get("curr_ipm") is not None:
                ipm_v = c["curr_ipm"] - c["prev_ipm"]
                ipm_display = f"{c['prev_ipm']:.2f}→{c['curr_ipm']:.2f}"
            else:
                ipm_v = c.get("ipm_chg")
                ipm_display = chg_str(c.get("ipm_chg"))
            rows += f"""<tr>
              <td>{c['flag']} {c['name']}</td>
              <td>${c['prev_cpi']:.2f}</td><td>${c['curr_cpi']:.2f}</td>
              <td class="{cls}">{badge}</td>
              <td class="{chg_class(cpm_v)}">{cpm_display}</td>
              <td class="{chg_class(ipm_v)}">{ipm_display}</td>
            </tr>"""
        body = f"""
    <div style="padding:16px 20px 8px;">
      <div style="display:inline-block;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:20px;padding:4px 14px;font-size:12px;color:#16a34a;font-weight:600;margin-bottom:12px;">✓ 本周期无国家 CPI 涨跌幅 ≥10%，整体表现良好</div>
    </div>
    <div style="padding:0 20px 16px;">
      <table>
        <tr><th>国家</th><th>CPI 上期</th><th>CPI 本期</th><th>CPI 变化</th><th>CPM</th><th>IPM</th></tr>
        {rows}
      </table>
    </div>"""
        alert_badge = f'<span style="margin-left:auto;font-size:12px;background:#f0fdf4;color:#16a34a;border:1px solid #bbf7d0;border-radius:20px;padding:2px 10px;">✓ 无预警</span>'
        return f"""
<div id="{key}" class="tab-content">
  <div class="product-header">
    <span class="product-id-badge">{prod['label']}</span>
    <span class="{os_cls} os-badge">{os_label}</span>
    <h2>{prod['name']} · {prod['product_id']}</h2>
    {alert_badge}
  </div>
  {body}
</div>"""

    # normal product with countries
    countries = prod.get("countries", [])
    alert_countries = [c for c in countries if abs(c["cpi_chg"]) >= 10]
    up_count = sum(1 for c in alert_countries if c["cpi_chg"] > 0)
    down_count = sum(1 for c in alert_countries if c["cpi_chg"] < 0)
    cnt = len(alert_countries)
    body = "".join(render_country_block(c) for c in countries)

    if cnt == 0:
        alert_badge = f'<span style="margin-left:auto;font-size:12px;background:#f0fdf4;color:#16a34a;border:1px solid #bbf7d0;border-radius:20px;padding:2px 10px;">✓ 无预警</span>'
    else:
        parts = []
        if up_count: parts.append(f'<span style="color:#dc2626">↑{up_count}</span>')
        if down_count: parts.append(f'<span style="color:#16a34a">↓{down_count}</span>')
        inner = " ".join(parts)
        alert_badge = f'<span class="alert-count">{inner} 国家预警</span>'

    return f"""
<div id="{key}" class="tab-content">
  <div class="product-header">
    <span class="product-id-badge">{prod['label']}</span>
    <span class="{os_cls} os-badge">{os_label}</span>
    <h2>{prod['name']} · {prod['product_id']}</h2>
    {alert_badge}
  </div>
  {body}
</div>"""


def make_tab_badge(prod):
    if prod.get("no_data"):
        return '<span class="badge pending">—</span>'
    if prod.get("no_alert"):
        return '<span class="badge ok">✓</span>'
    countries = prod.get("countries", [])
    cnt = sum(1 for c in countries if abs(c["cpi_chg"]) >= 10)
    up = sum(1 for c in countries if c["cpi_chg"] >= 10)
    down = sum(1 for c in countries if c["cpi_chg"] <= -10)
    if cnt == 0:
        return '<span class="badge ok">✓</span>'
    parts = []
    if up:   parts.append(f'<span style="color:#fecaca">↑{up}</span>')
    if down: parts.append(f'<span style="color:#bbf7d0">↓{down}</span>')
    return f'<span class="badge">{" ".join(parts)}</span>'


def generate_html(d):
    pc = d["period_curr"]
    pp = d["period_prev"]
    accounts = d["accounts"]

    # Flatten all products for tab content rendering
    all_products = [p for acc in accounts for p in acc["products"]]

    # Build tab groups HTML
    tab_groups_html = ""
    for acc in accounts:
        btns = ""
        first_key = acc["products"][0]["key"] if acc["products"] else ""
        for prod in acc["products"]:
            os_cls = "os-ios" if prod["os"] == "iOS" else "os-and"
            badge = make_tab_badge(prod)
            btns += f'<button class="tab-btn" id="btn-{prod["key"]}" onclick="switchTab(\'{prod["key"]}\')">{prod["label"]} <span class="{os_cls} os-badge-sm">{prod["os"]}</span> {badge}</button>\n'
        tab_groups_html += f"""
    <div class="tab-group">
      <div class="tab-group-label">{acc['label']} <span class="acc-id">{acc['id']}</span></div>
      <div class="tab-btns">{btns}</div>
    </div>"""

    # Tab contents
    tab_contents = "\n".join(render_product_tab(p) for p in all_products)

    # First tab key for JS init
    first_key = all_products[0]["key"] if all_products else ""

    # All keys for JS
    all_keys_js = "[" + ",".join(f"'{p['key']}'" for p in all_products) + "]"

    return f"""<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>TikTok 投放数据归因 | {pc}</title>
<style>
  * {{ box-sizing: border-box; margin: 0; padding: 0; }}
  body {{ font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; font-size: 13px; background: #f4f6f9; color: #1a1a2e; }}
  .page {{ max-width: 1280px; margin: 0 auto; padding: 20px; }}

  /* Password gate */
  #pw-gate {{
    position: fixed; inset: 0; z-index: 9999;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
    display: flex; align-items: center; justify-content: center;
  }}
  #pw-box {{
    background: white; border-radius: 16px; padding: 36px 40px; width: 320px;
    box-shadow: 0 20px 60px rgba(0,0,0,0.5); text-align: center;
  }}
  #pw-box .lock {{ font-size: 36px; margin-bottom: 12px; }}
  #pw-box h2 {{ font-size: 16px; font-weight: 700; color: #1e293b; margin-bottom: 4px; }}
  #pw-box p {{ font-size: 12px; color: #94a3b8; margin-bottom: 20px; }}
  #pw-input {{
    width: 100%; padding: 11px 14px; border: 1.5px solid #e2e8f0; border-radius: 8px;
    font-size: 15px; letter-spacing: 4px; text-align: center; outline: none;
    transition: border-color 0.2s;
  }}
  #pw-input:focus {{ border-color: #6366f1; }}
  #pw-input.error {{ border-color: #ef4444; animation: shake 0.3s; }}
  #pw-err {{ font-size: 12px; color: #ef4444; margin-top: 8px; min-height: 16px; }}
  #pw-btn {{
    margin-top: 16px; width: 100%; padding: 11px; background: #6366f1;
    color: white; border: none; border-radius: 8px; font-size: 14px;
    font-weight: 600; cursor: pointer; transition: background 0.2s;
  }}
  #pw-btn:hover {{ background: #4f46e5; }}
  @keyframes shake {{
    0%,100% {{ transform: translateX(0); }}
    25% {{ transform: translateX(-6px); }}
    75% {{ transform: translateX(6px); }}
  }}

  .report-header {{ background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%); color: white; border-radius: 12px; padding: 22px 28px; margin-bottom: 16px; }}
  .report-header h1 {{ font-size: 20px; font-weight: 700; }}
  .report-header .period {{ margin-top: 8px; font-size: 13px; opacity: 0.9; }}
  .report-header .period .curr {{ background: rgba(255,255,255,0.15); border-radius: 6px; padding: 3px 10px; margin-right: 8px; }}
  .report-header .period .prev {{ opacity: 0.6; font-size: 12px; }}
  .report-header .meta {{ margin-top: 8px; font-size: 11px; opacity: 0.55; }}

  /* Tab groups */
  .tab-groups {{ display: flex; flex-direction: column; gap: 0; margin-bottom: 0; }}
  .tab-group {{ display: flex; align-items: center; gap: 4px; flex-wrap: wrap; background: #f8fafc; border: 1px solid #e2e8f0; border-bottom: none; border-radius: 10px 10px 0 0; padding: 8px 12px 0; }}
  .tab-group:not(:first-child) {{ border-top: none; border-radius: 0; }}
  .tab-group-label {{ font-size: 10px; font-weight: 700; color: #94a3b8; text-transform: uppercase; letter-spacing: 0.5px; white-space: nowrap; padding: 0 6px 8px 0; border-right: 1px solid #e2e8f0; margin-right: 4px; }}
  .acc-id {{ font-weight: 400; color: #cbd5e1; }}
  .tab-btns {{ display: flex; gap: 3px; flex-wrap: wrap; padding-bottom: 0; }}
  .tab-btn {{ padding: 6px 12px; border-radius: 6px 6px 0 0; border: 1px solid #e2e8f0; border-bottom: none; background: #f1f5f9; cursor: pointer; font-size: 12px; font-weight: 600; color: #64748b; transition: all 0.15s; display: flex; align-items: center; gap: 4px; margin-bottom: 0; }}
  .tab-btn:hover {{ background: #e8edf5; }}
  .tab-btn.active {{ background: white; color: #1e293b; border-color: #e2e8f0; position: relative; z-index: 1; }}
  .badge {{ display: inline-block; background: #ef4444; color: white; border-radius: 10px; padding: 1px 6px; font-size: 10px; }}
  .badge.ok {{ background: #22c55e; }}
  .badge.pending {{ background: #94a3b8; }}

  /* OS badges */
  .os-badge {{ border-radius: 4px; padding: 1px 5px; font-size: 10px; font-weight: 700; }}
  .os-badge-sm {{ border-radius: 3px; padding: 0px 4px; font-size: 9px; font-weight: 700; }}
  .os-and {{ background: #dcfce7; color: #15803d; }}
  .os-ios {{ background: #dbeafe; color: #1d4ed8; }}

  .tab-content {{ display: none; background: white; border-radius: 0 0 12px 12px; border: 1px solid #e2e8f0; overflow: hidden; box-shadow: 0 1px 4px rgba(0,0,0,0.06); }}
  .tab-content.active {{ display: block; }}

  .product-header {{ padding: 14px 20px; background: #f8fafc; border-bottom: 1px solid #e2e8f0; display: flex; align-items: center; gap: 8px; flex-wrap: wrap; }}
  .product-id-badge {{ background: #1e293b; color: white; border-radius: 6px; padding: 3px 10px; font-size: 12px; font-weight: 700; }}
  .product-header h2 {{ font-size: 13px; font-weight: 600; color: #334155; }}
  .alert-count {{ margin-left: auto; font-size: 12px; background: #fef2f2; color: #dc2626; border: 1px solid #fecaca; border-radius: 20px; padding: 2px 10px; }}

  .country-block {{ border-bottom: 1px solid #f1f5f9; }}
  .country-block:last-child {{ border-bottom: none; }}
  .country-header {{ padding: 12px 20px; display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }}
  .country-name {{ font-size: 14px; font-weight: 600; }}
  .cpi-badge {{ border-radius: 20px; padding: 3px 12px; font-size: 12px; font-weight: 700; }}
  .cpi-up {{ background: #fef2f2; color: #dc2626; border: 1px solid #fecaca; }}
  .cpi-down {{ background: #f0fdf4; color: #16a34a; border: 1px solid #bbf7d0; }}
  .attr-badge {{ border-radius: 20px; padding: 3px 10px; font-size: 11px; margin-left: 4px; }}
  .attr-media {{ background: #fff7ed; color: #ea580c; border: 1px solid #fed7aa; }}
  .attr-creative {{ background: #fdf4ff; color: #9333ea; border: 1px solid #e9d5ff; }}
  .attr-both {{ background: #eff6ff; color: #2563eb; border: 1px solid #bfdbfe; }}

  .attr-section {{ padding: 10px 20px 0; }}
  .attr-bar-wrap {{ display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }}
  .attr-bar {{ flex: 1; height: 8px; background: #f1f5f9; border-radius: 4px; overflow: hidden; display: flex; }}
  .attr-media-fill {{ background: #f97316; height: 100%; }}
  .attr-creative-fill {{ background: #a855f7; height: 100%; }}
  .attr-labels {{ font-size: 11px; color: #64748b; white-space: nowrap; }}
  .attr-labels span {{ margin-right: 12px; }}
  .attr-labels .dot {{ display: inline-block; width: 8px; height: 8px; border-radius: 50%; margin-right: 3px; vertical-align: middle; }}

  .metrics-grid {{ display: flex; gap: 8px; padding: 0 20px 12px; flex-wrap: wrap; }}
  .metric-pill {{ background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 8px 12px; min-width: 100px; }}
  .metric-pill .m-label {{ font-size: 10px; color: #94a3b8; text-transform: uppercase; }}
  .metric-pill .m-val {{ font-size: 12px; font-weight: 600; margin: 2px 0; }}
  .metric-pill .m-chg {{ font-size: 11px; }}
  .chg-up {{ color: #dc2626; font-weight: 600; }}
  .chg-down {{ color: #16a34a; font-weight: 600; }}
  .chg-flat {{ color: #94a3b8; }}

  .table-section {{ padding: 0 20px 16px; }}
  .table-title {{ font-size: 11px; font-weight: 600; color: #475569; text-transform: uppercase; letter-spacing: 0.5px; margin: 12px 0 6px; display: flex; align-items: center; gap: 5px; }}
  .icon {{ width: 16px; height: 16px; border-radius: 4px; display: inline-flex; align-items: center; justify-content: center; font-size: 10px; font-weight: 700; flex-shrink: 0; }}
  .icon-media {{ background: #fff7ed; color: #ea580c; }}
  .icon-creative {{ background: #fdf4ff; color: #9333ea; }}
  .icon-pub {{ background: #eff6ff; color: #2563eb; }}
  .icon-fmt {{ background: #f0fdf4; color: #16a34a; }}
  table {{ width: 100%; border-collapse: collapse; font-size: 12px; }}
  th {{ background: #f8fafc; color: #64748b; font-size: 11px; font-weight: 600; padding: 7px 10px; text-align: left; border-bottom: 1px solid #e2e8f0; white-space: nowrap; }}
  td {{ padding: 7px 10px; border-bottom: 1px solid #f1f5f9; white-space: nowrap; }}
  tr:last-child td {{ border-bottom: none; }}
  tr:hover td {{ background: #fafbfd; }}
  .name-cell {{ max-width: 220px; overflow: hidden; text-overflow: ellipsis; }}
  .share-up {{ color: #f97316; font-weight: 600; }}
  .share-down {{ color: #64748b; }}
  .tag {{ font-size: 10px; border-radius: 3px; padding: 1px 5px; }}
  .tag-warn {{ background: #fef2f2; color: #dc2626; border: 1px solid #fecaca; }}
  .tag-ok {{ background: #f0fdf4; color: #16a34a; border: 1px solid #bbf7d0; }}
  .fmt-badge {{ background: #f1f5f9; color: #334155; border: 1px solid #e2e8f0; border-radius: 4px; padding: 1px 6px; font-size: 11px; font-weight: 600; }}
  .pending-msg {{ background: #fafafa; border: 1px dashed #e2e8f0; border-radius: 8px; padding: 10px 14px; font-size: 12px; color: #94a3b8; margin: 8px 0; }}

  .conclusion {{ margin: 0 20px 16px; background: #f8fafc; border-left: 3px solid #6366f1; border-radius: 0 8px 8px 0; padding: 10px 14px; font-size: 12px; color: #334155; line-height: 1.6; }}
  .conclusion strong {{ color: #1e293b; }}

  .copy-btn {{ position: fixed; bottom: 24px; right: 24px; background: #6366f1; color: white; border: none; border-radius: 50px; padding: 11px 20px; font-size: 13px; font-weight: 600; cursor: pointer; box-shadow: 0 4px 14px rgba(99,102,241,0.4); z-index: 100; }}
  .copy-btn:hover {{ background: #4f46e5; }}
  @media print {{ .copy-btn {{ display: none; }} }}
</style>
</head>
<body>

<!-- Password gate -->
<div id="pw-gate">
  <div id="pw-box">
    <div class="lock">🔒</div>
    <h2>TikTok 投放数据归因</h2>
    <p>请输入访问密码</p>
    <input id="pw-input" type="password" placeholder="密码" autocomplete="off"
           onkeydown="if(event.key==='Enter')checkPw()">
    <div id="pw-err"></div>
    <button id="pw-btn" onclick="checkPw()">进入</button>
  </div>
</div>

<div class="page">

<div class="report-header">
  <h1>TikTok 投放数据归因周报</h1>
  <div class="period">
    <span class="curr">📅 本期：{pc}</span>
    <span class="prev">对比上期：{pp}</span>
  </div>
  <div class="meta">筛选条件：CPI 涨跌幅 ≥10% · 数据源：fact_dsp_core (gross_spend_usd) · 生成于 {d['generated_at']}</div>
</div>

<div class="tab-groups">
{tab_groups_html}
</div>

{tab_contents}

</div>

<button class="copy-btn" onclick="copyText()">📋 复制摘要</button>

<script>
(function() {{
  if (sessionStorage.getItem('tt_auth') === '1') {{
    document.getElementById('pw-gate').style.display = 'none';
  }}
}})();

function checkPw() {{
  const val = document.getElementById('pw-input').value;
  if (val === 'TT') {{
    sessionStorage.setItem('tt_auth', '1');
    document.getElementById('pw-gate').style.display = 'none';
  }} else {{
    const inp = document.getElementById('pw-input');
    inp.classList.remove('error'); void inp.offsetWidth; inp.classList.add('error');
    document.getElementById('pw-err').textContent = '密码错误，请重试';
    inp.value = '';
  }}
}}

const ALL_KEYS = {all_keys_js};

function switchTab(id) {{
  ALL_KEYS.forEach(k => {{
    const el = document.getElementById(k);
    const btn = document.getElementById('btn-' + k);
    if (el) el.classList.remove('active');
    if (btn) btn.classList.remove('active');
  }});
  const el = document.getElementById(id);
  const btn = document.getElementById('btn-' + id);
  if (el) el.classList.add('active');
  if (btn) btn.classList.add('active');
}}

// Init first tab
switchTab('{first_key}');

function copyText() {{
  const active = document.querySelector('.tab-content.active');
  if (!active) return;
  const text = active.innerText.replace(/\\n{{3,}}/g, '\\n\\n');
  navigator.clipboard.writeText(text).then(() => {{
    const btn = document.querySelector('.copy-btn');
    btn.textContent = '✓ 已复制';
    btn.style.background = '#22c55e';
    setTimeout(() => {{ btn.textContent = '📋 复制摘要'; btn.style.background = '#6366f1'; }}, 2000);
  }});
}}
</script>
</body>
</html>"""


def main():
    html = generate_html(REPORT_DATA)
    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        f.write(html)
    print(f"✓ 报告已生成: {OUTPUT_FILE}")

    repo = str(REPO_DIR)
    period = REPORT_DATA["period_curr"].replace(" ", "").replace("~", "-")
    msg = f"report: {period} CPI归因报告"
    subprocess.run(["git", "-C", repo, "add", "index.html", "generate_tt_report.py"], check=False)
    r = subprocess.run(["git", "-C", repo, "commit", "-m", msg], capture_output=True, text=True)
    if "nothing to commit" in r.stdout:
        print("✓ 无变更，无需推送")
    else:
        subprocess.run(["git", "-C", repo, "push", "--set-upstream", "origin", "main"], check=False)
        print("✓ 已推送到 GitHub Pages")


if __name__ == "__main__":
    main()
